{
  "title": "लाइफटाइम एनोटेशन",
  "group": "लाइफटाइम्स",
  "options": [
    {
      "text": "परिणाम: सेनेका द यंगर",
      "hint": "कोड कंपाइल ही नहीं होगा, इसलिए कोई आउटपुट नहीं मिलेगा"
    },
    {
      "text": "त्रुटि: लाइफटाइम स्पेसिफायर गायब है"
    },
    {
      "text": "त्रुटि: लोकल वेरिएबल का रेफरेंस रिटर्न नहीं किया जा सकता",
      "hint": "यह रेफरेंस किसी लोकल वेरिएबल का नहीं, बल्कि इनपुट पैरामीटर का है"
    },
    {
      "text": "त्रुटि: लाइफटाइम मिसमैच",
      "hint": "हमने अभी तक लाइफटाइम स्पेसिफाई ही नहीं किए हैं, तो मिसमैच कहाँ से आएगा?"
    }
  ],
  "questionProse": [
    "दो स्ट्रिंग स्लाइस में से लंबी वाली को रिटर्न करने वाले इस फंक्शन के साथ क्या होगा?"
  ],
  "explanationProse": [
    "यह कोड फेल हो जाता है क्योंकि कंपाइलर इनपुट और आउटपुट लाइफटाइम्स के बीच के संबंध को समझ नहीं पाता। यहाँ बताया गया है कि ऐसा क्यों होता है और इसे कैसे ठीक करें:",
    "यहाँ लाइफटाइम्स की ज़रूरत क्यों है:\n      1. कई इनपुट रेफरेंस की लाइफटाइम अलग-अलग हो सकती है\n      2. रिटर्न वैल्यू को दोनों इनपुट्स जितनी देर तक जीवित रहना चाहिए\n      3. कंपाइलर को इन संबंधों को वेरिफाई करने की ज़रूरत होती है\n\n      कॉमन पैटर्न:",
    "बेस्ट प्रैक्टिसेज़:\n      1. जहाँ संभव हो, लाइफटाइम एलिज़न को काम करने दें\n      2. जब संबंध स्पष्ट करने हों, तो एक्सप्लिसिट लाइफटाइम्स का उपयोग करें\n      3. लाइफटाइम की जटिलता से बचने के लिए ओन्ड टाइप्स रिटर्न करने पर विचार करें\n      4. कॉम्प्लेक्स लाइफटाइम संबंधों को डॉक्युमेंट करें"
  ]
}
